Scan a directory for images matching a pattern and map them to Stream Deck key indices.

## Implementation

```rust
// src/batch/scanner.rs
use std::path::{Path, PathBuf};
use tracing::{debug, trace, info, warn, instrument};

#[derive(Debug, Clone)]
pub struct ScanResult {
    pub mappings: Vec<KeyMapping>,
    pub unmatched: Vec<PathBuf>,
    pub invalid: Vec<(PathBuf, String)>,
}

#[derive(Debug, Clone)]
pub struct KeyMapping {
    pub key: u8,
    pub path: PathBuf,
    pub size_bytes: u64,
}

/// Scan a directory for files matching the pattern
#[instrument(fields(dir = %dir.display(), pattern = %pattern))]
pub fn scan_directory(
    dir: &Path,
    pattern: &str,
    key_count: u8,
) -> Result<ScanResult, ScanError> {
    info!("Starting directory scan");

    if !dir.exists() {
        return Err(ScanError::DirectoryNotFound(dir.to_path_buf()));
    }

    if !dir.is_dir() {
        return Err(ScanError::NotADirectory(dir.to_path_buf()));
    }

    let mut mappings = Vec::new();
    let mut unmatched = Vec::new();
    let mut invalid = Vec::new();

    let entries = std::fs::read_dir(dir)
        .map_err(|e| ScanError::ReadError(dir.to_path_buf(), e))?;

    for entry in entries {
        let entry = entry.map_err(|e| ScanError::EntryError(e))?;
        let path = entry.path();

        // Skip directories
        if path.is_dir() {
            trace!(path = %path.display(), "Skipping directory");
            continue;
        }

        // Try to extract key index from filename
        match extract_key_index(&path, pattern) {
            Some(key) if key < key_count => {
                let metadata = std::fs::metadata(&path)?;
                debug!(
                    key = %key,
                    path = %path.display(),
                    size = %metadata.len(),
                    "Matched key file"
                );
                mappings.push(KeyMapping {
                    key,
                    path,
                    size_bytes: metadata.len(),
                });
            }
            Some(key) => {
                warn!(
                    key = %key,
                    max = %key_count,
                    path = %path.display(),
                    "Key index out of range"
                );
                invalid.push((path, format!("key {} out of range (max {})", key, key_count - 1)));
            }
            None => {
                trace!(path = %path.display(), "File doesn't match pattern");
                unmatched.push(path);
            }
        }
    }

    // Sort mappings by key index for consistent ordering
    mappings.sort_by_key(|m| m.key);

    info!(
        matched = %mappings.len(),
        unmatched = %unmatched.len(),
        invalid = %invalid.len(),
        "Directory scan complete"
    );

    Ok(ScanResult { mappings, unmatched, invalid })
}

/// Extract key index from filename based on pattern
fn extract_key_index(path: &Path, pattern: &str) -> Option<u8> {
    let filename = path.file_name()?.to_str()?;

    // Pattern like "key-{index}.png" or "key-{index:02d}.png"
    // Find where {index} would be and extract the number there
    let parts: Vec<&str> = pattern.split("{index").collect();
    if parts.len() != 2 {
        return None;
    }

    let prefix = parts[0];
    let suffix = parts[1].split('}').nth(1)?;

    if !filename.starts_with(prefix) || !filename.ends_with(suffix) {
        return None;
    }

    let start = prefix.len();
    let end = filename.len() - suffix.len();
    let num_str = &filename[start..end];

    num_str.parse().ok()
}
```

## Edge Cases
- Empty directory → empty mappings, no error
- No matching files → empty mappings with all in unmatched
- Duplicate key indices → last one wins (warn logged)
- Symlinks → followed (like regular files)
- Permission denied on file → added to invalid with reason

## Logging Requirements
- TRACE: Each file examined (match/no-match decision)
- DEBUG: Each matched file with key index and size
- INFO: Scan start/complete with summary counts
- WARN: Key index out of range, duplicates
- ERROR: Directory access failures

