// src/config/path.rs
use std::path::{Path, PathBuf};
use crate::error::{Result, SdError};
use tracing::{debug, trace};

/// Resolve a path from a config file
/// 
/// Resolution rules:
/// 1. Absolute paths: used as-is
/// 2. Paths starting with ~: expanded to home directory
/// 3. Relative paths: resolved relative to config file's directory
pub fn resolve_path(path: &Path, config_dir: &Path) -> Result<PathBuf> {
    trace!(path = %path.display(), config_dir = %config_dir.display(), "Resolving path");

    let path_str = path.to_string_lossy();

    // Handle home directory expansion
    if path_str.starts_with("~/") || path_str == "~" {
        let home = home_dir()?;
        let rest = path_str.strip_prefix("~/").unwrap_or("");
        let resolved = home.join(rest);
        debug!(original = %path.display(), resolved = %resolved.display(), "Expanded ~ path");
        return Ok(resolved);
    }

    // Handle absolute paths
    if path.is_absolute() {
        debug!(path = %path.display(), "Using absolute path as-is");
        return Ok(path.to_path_buf());
    }

    // Handle relative paths
    let resolved = config_dir.join(path);
    debug!(
        original = %path.display(),
        config_dir = %config_dir.display(),
        resolved = %resolved.display(),
        "Resolved relative path"
    );

    Ok(resolved)
}

/// Get home directory cross-platform
pub fn home_dir() -> Result<PathBuf> {
    dirs::home_dir()
        .ok_or_else(|| SdError::ConfigInvalid(
            "Could not determine home directory".to_string()
        ))
}

/// Check if a path exists and is a file
pub fn validate_image_path(path: &Path) -> Result<()> {
    if !path.exists() {
        return Err(SdError::ImageNotFound(path.display().to_string()));
    }

    if !path.is_file() {
        return Err(SdError::ImageNotFound(
            format!("{} is not a file", path.display())
        ));
    }

    // Check extension for supported formats
    let ext = path.extension()
        .and_then(|e| e.to_str())
        .map(|e| e.to_lowercase());

    match ext.as_deref() {
        Some("png" | "jpg" | "jpeg" | "gif" | "bmp" | "webp") => Ok(()),
        Some(other) => Err(SdError::ImageFormat(
            format!("Unsupported image format: .{}", other)
        )),
        None => Err(SdError::ImageFormat(
            "Image file has no extension".to_string()
        )),
    }
}

/// Path resolution context for a config file
pub struct PathResolver {
    config_dir: PathBuf,
}

impl PathResolver {
    /// Create resolver for a config file path
    pub fn new(config_path: &Path) -> Result<Self> {
        let config_dir = config_path.parent()
            .ok_or_else(|| SdError::ConfigInvalid(
                format!("Config path has no parent directory: {}", config_path.display())
            ))?
            .to_path_buf();

        // Canonicalize if possible (resolves symlinks)
        let config_dir = config_dir.canonicalize()
            .unwrap_or(config_dir);

        Ok(Self { config_dir })
    }

    /// Resolve a path relative to config file
    pub fn resolve(&self, path: &Path) -> Result<PathBuf> {
        resolve_path(path, &self.config_dir)
    }

    /// Resolve and validate an image path
    pub fn resolve_image(&self, path: &Path) -> Result<PathBuf> {
        let resolved = self.resolve(path)?;
        validate_image_path(&resolved)?;
        Ok(resolved)
    }

    /// Get the config directory
    pub fn config_dir(&self) -> &Path {
        &self.config_dir
    }
}
