    #[arg(long, global = true, default_value = "1.5")]
    pub retry_backoff: f32,

    // ... existing fields ...
}
```

### ConnectionOptions Builder
```rust
impl GlobalOpts {
    /// Build ConnectionOptions from CLI flags
    pub fn connection_options(&self) -> ConnectionOptions {
        if self.retry == 0 {
            ConnectionOptions {
                max_retries: 1,  // Single attempt, no retry
                retry_delay: Duration::from_millis(0),
                backoff_factor: 1.0,
                max_delay: Duration::from_millis(0),
            }
        } else {
            ConnectionOptions {
                max_retries: self.retry,
                retry_delay: Duration::from_millis(self.retry_delay),
                backoff_factor: self.retry_backoff,
                max_delay: Duration::from_millis(self.retry_max_delay),
            }
        }
    }
}
